INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('คุณเพิ่งรับลูกหมาวัย 2 เดือนมาเลี้ยง ด้วยความที่อยากให้น้องเข้าสังคมเก่งๆ ไม่ตื่นกลัวหมาตัวอื่น คุณเลยจัดการใส่สายจูงพาไปลุย Dog Park ที่มีหมาวิ่งเล่นกันพลุกพล่านตั้งแต่สัปดาห์แรกซะเลย แผนนี้เวิร์คไหม?', NULL, 1, 'นี่คือข้อควรระวังอันดับ 1 ของคนได้ลูกหมาใหม่เลย! สุนัขที่อายุต่ำกว่า 4 เดือนและยังฉีดวัคซีนรวมไม่ครบ ห้ามพาไปเดินตามพื้นดินสาธารณะที่มีหมาจรหรือหมาแปลกหน้าเด็ดขาด เพราะเสี่ยงติดโรคลำไส้อักเสบติดต่อและไข้หัดสุนัข ซึ่งมีโอกาสเสียชีวิตสูงมาก การเข้าสังคมในวัยนี้ควรเริ่มจากการเจอหมาโตที่บ้านเพื่อน (ที่ฉีดวัคซีนครบและนิสัยดี) ในพื้นที่ปิดจะปลอดภัยกว่า'),
('น้องหมาของคุณส่งเสียงครางหงิงๆในลำคอ พร้อมกับเดินวนไปวนมาและใช้เท้าตะกุยที่หน้าประตูบ้าน สถานการณ์นี้เขาน่าจะกำลังพยายามบอกอะไรกับคุณ?', NULL, 1, 'เสียงครางหงิงๆ มักเป็นตัวแทนของความเครียด ความกังวล หรือความต้องการบางอย่างที่รอไม่ได้ เช่น ปวดปัสสาวะ/อุจจาระ (ส่วนการเตือนภัยมักจะใช้การเห่า)'),
('ระหว่างวิ่งเล่นกันอยู่ในสวน น้องหมาของคุณวิ่งไปคาบ "กิ่งไม้แห้ง" ที่ตกอยู่บนพื้นสนามหญ้า แล้ววิ่งเอามาวางตรงหน้าเพื่อให้คุณโยนเล่น คุณควรทำอย่างไรต่อไป?', NULL, 1, 'กิ่งไม้เป็นอันตรายกว่าที่คิด เพราะอาจแตกเป็นเสี้ยนทิ่มแทงทะลุเพดานปาก เหงือก หรือหากกลืนเข้าไปอาจทำให้ลำไส้อุดตันและทะลุได้');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('หลังจากพาน้องหมาไปลุยดงหญ้า กลับมาบ้านคุณลูบคลำไปเจอ "เห็บ" ตัวอ้วนเป่งกำลังดูดเลือดหนึบอยู่บนหลังน้อง วิธีเอาเห็บออกที่ถูกต้องและปลอดภัยที่สุดคือข้อไหน?', NULL, 2, 'การเอาไฟลน หรือใช้น้ำมันชโลม เป็นความเชื่อที่ผิดและอันตรายมาก! เพราะการทำให้เห็บตกใจ (ร้อนหรือสำลัก) จะทำให้เห็บขย้อนน้ำลายที่เต็มไปด้วยเชื้อโรค เช่น พยาธิเม็ดเลือด กลับเข้าไปในกระแสเลือดของสุนัขทันที การคีบออกตรงๆ แล้วเอาไปแช่น้ำยาล้างจานหรือแอลกอฮอล์คือวิธีที่ถูกต้องที่สุด'),
('คุณกลับมาถึงบ้านแล้วพบว่า หมอนอิงบนโซฟาถูกกัดจนนุ่นกระจายเต็มห้อง! พอคุณหันไปมองหน้าน้องหมา น้องก็ทำหน้าหงอยสุดๆ หูลู่ หลบตา คอตก เหมือนรู้ตัวว่าทำผิด อาการแบบนี้น้องกำลัง "สำนึกผิด" จริงๆ ใช่ไหมเนี่ย?', NULL, 2, 'สัตวแพทย์และผู้เชี่ยวชาญด้านพฤติกรรมสุนัขยืนยันว่า หมาไม่มีความรู้สึกซับซ้อนอย่างคำว่า "สำนึกผิด" แบบมนุษย์ หน้าจ๋อยๆ ที่เราเห็น เรียกว่า "Appeasement behavior" หรือพฤติกรรมยอมจำนน เพราะน้องสัมผัสได้ว่าเจ้านายกำลังอารมณ์ไม่ดีจากน้ำเสียงและท่าทาง เลยพยายามทำตัวให้เล็กลงเพื่อลดการปะทะนั่นเอง'),
('น้องหมาตัวแสบที่บ้านชอบเห่ามั่วซั่ว กัดทำลายข้าวของ และไม่ยอมฟังคำสั่ง คุณเลยตัดสินใจพาไป "ทำหมัน" โดยหวังว่าตื่นมาน้องจะกลายเป็นผ้าพับไว้ เรียบร้อยดั่งคุณหนู ความเชื่อนี้ถูกต้องไหม?', NULL, 2, 'ทำหมันไม่ใช่ยาวิเศษที่จะรีเซ็ตนิสัยหมาได้นะ มันช่วยลดความก้าวร้าวหรือความหงุดหงิดเวลาติดสัดได้จริง ลดการหนีเที่ยวได้จริง แต่นิสัยดื้อ กัดของ หรือไม่ฟังคำสั่ง เป็นเรื่องของการอบรมล้วนๆ ทำหมันเสร็จก็ยังต้องฝึกกันต่อไปนะ!');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('หากน้องหมาของคุณทำหน้าอ้อนขอกินองุ่นจากคุณ คุณควรให้พวกเขากินหรือไม่?', NULL, 3, 'ไม่ควรให้กินเด็ดขาด ผลไม้ชนิดนี้ไม่ว่าจะสดหรือตากแห้ง (ลูกเกด) ก็สามารถทำลายอวัยวะสำคัญในการกรองของเสียของสุนัขได้'),
('ในช่วงบ่ายวันหยุดที่แดดค่อนข้างจัด คุณอยากพาน้องหมาออกไปเดินเล่นที่สวนสาธารณะใกล้บ้าน ก่อนพาออกไปเดินบนถนนคอนกรีต คุณควรเช็คความพร้อมอย่างไรเพื่อความปลอดภัยของพวกเขา?', NULL, 3, 'ให้วางหลังมือของคุณทาบลงบนพื้นถนนทิ้งไว้ 5 วินาทีเพื่อทดสอบความร้อน หากหลังมือของคุณทนความร้อนจากพื้นถนนได้ไม่ถึง 5 วินาที แปลว่าพื้นนั้นร้อนเกินกว่าที่อุ้งเท้าบอบบางของสุนัขจะรับได้ และอาจทำให้เกิดแผลพุพองอย่างรุนแรง'),
('หลังจากพาน้องหมาไปขึ้นเขียง "ทำหมัน" เรียบร้อย แผลหายดี ผ่านไปแค่ไม่กี่เดือน ทำไมน้องถึงตัวบวมขึ้นเป็นถังแก๊สได้ล่ะเนี่ย!? สาเหตุหลักๆ ที่ทำให้น้องหมาอ้วนขึ้นหลังทำหมันคืออะไร?', NULL, 3, 'นี่คือเรื่องคลาสสิกที่คนเลี้ยงหมาต้องเจอ พอตัดฮอร์โมนเพศออกปุ๊บ ระบบเผาผลาญพลังงาน จะลดลงประมาณ 20-30% ทันที ดังนั้นถ้าเจ้าของยังให้ข้าวปริมาณเท่าเดิมเป๊ะ น้องจะอ้วนขึ้นแบบก้าวกระโดดชัวร์ๆ ต้องลดปริมาณอาหารหรือเปลี่ยนเป็นสูตรทำหมันนะ');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('จู่ๆ เจ้าสี่ขาก็เมินอาหารเม็ดชามโปรด ดมฟุดฟิดสองทีแล้วเดินหนี แต่พอคุณนั่งกินหมูปิ้ง น้องกลับมานั่งทำตาละห้อย น้ำลายยืดขอแจมด้วย สรุปว่าน้องดื้อเลือกกิน หรือมีอะไรซ่อนอยู่?', NULL, 4, 'ปัญหาช่องปาก น้องอาจจะปวดเหงือก ฟันผุ หรือเคี้ยวของแข็งๆ ไม่ไหวแล้ว หมาแก่ไม่ได้เบื่ออาหารเสมอไป แต่โรคพวกหินปูน เหงือกอักเสบ ฟันโยก มักจะถามหาในวัยนี้ ทำให้เจ็บปวดเวลาเคี้ยวอาหารเม็ดแข็งๆ แต่พวกของนิ่มๆ หอมๆ อย่างหมูปิ้งน้องยังกลืนได้สบาย ถ้าเจอแบบนี้ให้ลองเอาอาหารเม็ดแช่น้ำซุปอุ่นๆ ให้นิ่ม หรือเปลี่ยนเป็นอาหารเปียกดู'),
('น้องหมาที่เคยฉี่เป็นที่เป็นทางมาตลอดชีวิต จู่ๆ ก็นอนหลับแล้วฉี่ราดใส่ที่นอนตัวเอง แถมตื่นมายังทำหน้างงๆ ดมฉี่ตัวเองแบบไม่รู้ตัวอีก พฤติกรรมนี้เกิดจากสาเหตุอะไร?', NULL, 4, 'หูรูดกระเพาะปัสสาวะเสื่อมตามวัย ทำให้กลั้นไม่อยู่ตอนหลับลึก อาการปัสสาวะเล็ด เป็นเรื่องปกติทางการแพทย์ที่พบได้บ่อยมากในหมาแก่ โดยเฉพาะตัวเมียที่ทำหมันแล้ว กล้ามเนื้อหูรูดจะหย่อนยานเวลาน้องหลับลึก ห้ามดุหรือทำโทษเด็ดขาดเพราะน้องไม่ได้ตั้งใจและควบคุมไม่ได้จริงๆ วิธีแก้คือใส่ผ้าอ้อมสุนัข หรือพาไปพบสัตวแพทย์'),
('น้องหมาวัย 12 ปี พยายามจะลุกขึ้นจากเบาะนอนเพื่อเดินมากินน้ำ แต่พอเท้าแตะพื้นกระเบื้องแกรนิตโต้เงาวับปุ๊บ ขาหลังก็ลื่นไถลแยกออกจากกัน ลุกไม่ขึ้น พยายามตะเกียกตะกายจนดูเหมือนกวางน้อยเพิ่งหัดเดิน เพื่อช่วยเซฟช่วงล่างของคุณตา วิธีแก้ปัญหาที่ตรงจุดและปลอดภัยที่สุดคืออะไร?', NULL, 4, 'ควักกระเป๋าเปย์ แผ่นยางกันลื่น หรือพรม มาปูลาดตระเวนตามทางเดินหลักๆ ที่น้องใช้ประจำ การปรับสภาพแวดล้อม คือวิธีที่ดีที่สุดและยั่งยืนที่สุด หมาแก่ที่กล้ามเนื้อฝ่อลงจะไม่มีแรงจิกปลายเท้าเพื่อเบรกบนพื้นลื่นๆ อีกต่อไป การปูพรมหรือแผ่นยางกันลื่นตามจุดสำคัญ จะช่วยสร้างความมั่นใจให้น้องก้าวเดินได้เต็มฝ่าเท้าโดยไม่ต้องเกร็งจนกล้ามเนื้ออักเสบ');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('ลูกปอมวัย 4-5 เดือนของคุณที่เคยขนฟูฟ่องเป็นก้อนเมฆ จู่ๆ ขนก็เริ่มร่วงแหว่งเป็นหย่อมๆ โดยเฉพาะรอบๆ หน้า จนขนรอบดวงตาดูสั้นเตียน หน้าตาตลกคล้ายกับ "ลูกลิง" คุณเริ่มแพนิกว่าน้องเป็นขี้เรื้อนหรือเปล่า ความจริงคืออะไร?', 1, 1, 'เป็นเรื่องธรรมชาติ เรียกว่า ช่วงผลัดขนวัยเด็ก หรือ Monkey Stage ใครเลี้ยงปอมต้องเจอช่วงหน้าลิงกันทุกคน เป็นวัยที่น้องกำลังผลัดขนอ่อนทิ้ง เพื่อให้ขนผู้ใหญ่ที่หนาและสวยกว่างอกขึ้นมาแทนที่'),
('ใบไม้ร่วง... เห่า! นกบินผ่าน... เห่า! คนข้างบ้านเดินไปทิ้งขยะ... เห่า! ลูกปอมวัย 4 เดือนของคุณเสียงเห่าแหลมปรี๊ดดดด ทะลุแก้วหูจนเพื่อนบ้านเริ่มมองแรง ถ้าปล่อยไว้โตไปได้ปวดหัวแน่ วิธีดับเครื่องชนปัญหานี้คือ?', 1, 1, 'พอเริ่มเห่าปุ๊บ ให้เบี่ยงเบนความสนใจด้วยของเล่นหรือคำสั่ง พอหยุดเห่าปั๊บให้รีบให้ขนมเป็นรางวัล ปอมเป็นหมาตื่นตัวสูง การตะโกนด่า น้องจะนึกว่าเรากำลังเห่าช่วยกัน! วิธีที่ดีที่สุดคือฝึกให้น้องรู้ว่า "ความเงียบ = ได้ขนม"');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('คุณพาเจ้าปอมวัย 8 เดือนไปเดินเล่นสวนสาธารณะ บังเอิญมีโกลเด้นตัวเบ้อเริ่มเดินผ่านมาแบบนิ่งๆ แต่เจ้าปอมของคุณกลับพุ่งตัวเข้าใส่ เห่ากรรโชกเสียงแหลมปรี๊ดดดด ทำตัวพองลม! พฤติกรรมห้าวเป้งไม่เจียมบอดี้แบบนี้เกิดจากอะไร?', 1, 2, 'เป็น Small Dog Syndrome หรืออาการหมาเล็กคิดว่าตัวเองใหญ่ มักเกิดจากการที่เจ้าของโอ๋เกินไป พอหมาตัวเล็กทำท่าก้าวร้าว คนมักจะมองว่าน่ารักแล้วเข้าไปอุ้มปลอบ พฤติกรรมนี้ถ้าปล่อยไว้น้องจะเครียดง่ายและอาจโดนหมาใหญ่กัดเอาได้จริงๆ'),
('ถึงเวลาพาลูกปอมออกไปเดินโชว์ตัวหน้าบ้านครั้งแรก คุณกำลังยืนเลือกอุปกรณ์ระหว่าง "ปลอกคอเส้นเล็กน่ารักๆ" กับ "สายรัดอก" สำหรับสายพันธุ์นี้ อุปกรณ์แบบไหนปลอดภัยต่อสุขภาพระยะยาวมากกว่ากัน?', 1, 2, 'สายรัดอก เพราะช่วงคอและหลอดลมของปอมนั้นบอบบางมาก เสี่ยงต่อภาวะหลอดลมตีบเทียม การใส่ปลอกคอแล้วน้องดึง จะไปสร้างแรงกดทับที่หลอดลมโดยตรง จนทำให้น้องไอแห้งๆ การใช้สายรัดอกจึงเซฟสุขภาพกว่ามาก'),
('คุณเพิ่งเปิดประตูเข้าบ้าน เจ้าปอมดีใจสุดขีด กระโดดสปริงบอร์ดต้อนรับคุณ แต่จู่ๆ ก็ทำเสียง "ครืดดดด แคร่กๆๆ" คล้ายเสียงห่านร้อง คอยืด คอตก เหมือนคนหายใจไม่ออกไปชั่วขณะ อาการชวนตกใจนี้คือสัญญาณเตือนของอะไร?', 1, 2, 'ภาวะหลอดลมตีบเทียม หลอดลมพับตัวลงชั่วคราว กระดูกอ่อนที่หลอดลมของสุนัขพันธุ์เล็กมักจะอ่อนแอและแบนราบลงได้ง่ายเมื่อน้องหมาตื่นเต้นจัด หรือดึงสายจูงแรงๆ เสียงห่านร้องนี้คือคีย์เวิร์ดสำคัญของโรคนี้เลย');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('ด้วยความที่ปอมมีขนสองชั้นที่หนาฟูมหาศาล ทำให้การกะด้วยสายตาว่า "ตอนนี้น้องอ้วนหรือผอม" เป็นเรื่องที่ยากมาก วิธีเช็คหุ่นที่แม่นยำที่สุดสำหรับหมาขนฟูคืออะไร?', 1, 3, 'ใช้มือลูบคลำที่บริเวณซี่โครง ถ้าลูบแล้วเจอซี่โครงได้ง่ายๆ โดยไม่ต้องออกแรงกด แปลว่าหุ่นกำลังดี ขนฟูๆ มักจะหลอกตาเจ้าของเสมอ วิธีที่สัตวแพทย์แนะนำคือการ "ลูบซี่โครง"'),
('ปอมวัย 5 ปีของคุณกินเก่ง ร่าเริงดีทุกอย่าง แต่พออ้าปากหาวทีไร กลิ่นโชยมาเหมือนท่อระบายน้ำ แถมตรงโคนฟันกรามมีคราบสีเหลืองเกาะหนาเตอะ ถ้าคุณปล่อยเบลอไม่ยอมพาไปขูดหินปูน จะเกิดผลเสียร้ายแรงที่สุดคืออะไร?', 1, 3, 'แบคทีเรียจากเหงือกอักเสบจะซึมเข้ากระแสเลือด ไปทำลายลิ้นหัวใจและไต จนถึงขั้นเสียชีวิตได้ ปอมเป็นสายพันธุ์ที่ขากรรไกรเล็กแต่ฟันเยอะ หินปูนเลยขึ้นไว การแปรงฟันทุกวันและพาไปขูดหินปูนจึงเป็นเรื่องบังคับ');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('ตอนนี้คุณตาปอมวัย 13 ปี กลายเป็น "คุณตาเหงือกบาน" เพราะฟันร่วงและโดนหมอถอนออกจนแทบจะหมดปากแล้ว! คุณควรปรับเปลี่ยนวิธีให้อาหารยังไงให้น้องยังได้สารอาหารครบถ้วนและไม่ทรมานตอนกิน?', 1, 4, 'เอาอาหารเม็ดสูตรหมาแก่ไปแช่น้ำอุ่นให้นิ่ม หรือเปลี่ยนเป็นอาหารเปียก/สับละเอียด หมาแก่พันธุ์เล็กที่ฟันร่วงหมดปากเป็นเรื่องปกติมากๆ การนำอาหารเม็ดไปแช่น้ำอุ่นจนบานและนิ่มเละ จะช่วยให้น้องใช้เหงือกดุนๆ กลืนได้สบาย'),
('จู่ๆ คุณก็สังเกตเห็นว่าดวงตากลมโตสุดแบ๊วของคุณยายปอมวัย 12 ปี มี "ฝ้าสีขาวขุ่นอมฟ้า" มาบังตรงกลางตาดำ คุณตกใจมากนึกว่าน้องตาบอดไปแล้ว แต่พอลองโยนขนมชิ้นเล็กๆ ลงพื้น น้องกลับวิ่งไปตะปบกินได้แม่นยำเป๊ะ! ฝ้าขาวๆ นี้คืออะไรกันแน่?', 1, 4, 'ภาวะเลนส์ตาเสื่อมตามวัย ซึ่งเป็นเรื่องธรรมชาติ น้องยังพอมองเห็นได้ เลนส์ตาจะแข็งและดูขุ่นขึ้น แต่แสงยังผ่านได้ น้องจึงยังพอมองเห็นและใช้ชีวิตได้ปกติ ต่างจากโรค "ต้อกระจก" ที่ตาจะขุ่นขาวทึบและทำให้ตาบอดจริงๆ');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('คุณพาลูกสุนัขบีเกิลวัย 3 เดือนไปวิ่งเล่นที่สนามหญ้า คุณพยายามเรียกชื่อและโยนลูกบอลให้เล่น แต่เขากลับเอาแต่ก้มหน้าดมพื้นดินไปมาอย่างเอาเป็นเอาตาย และเริ่มส่งเสียงร้องยาวๆ โดยไม่สนใจคุณเลย คุณควรจัดการอย่างไร?', 2, 1, 'ปล่อยให้เขาดมต่อไปเพราะมันคือสัญชาตญาณ แต่ต้องอยู่ในสายจูงหรือรั้วที่มิดชิด บีเกิลเป็นสุนัขล่าสัตว์ตระกูล Scent Hound เมื่อจมูกล็อคเป้าหมายกลิ่นได้แล้ว สมองส่วนการได้ยินจะแทบถูกปิดสวิตช์ ผู้เลี้ยงควรเข้าใจและจัดพื้นที่ปลอดภัยให้เขาได้สำรวจกลิ่น'),
('ถึงเวลานอนแล้ว แต่บีเกิลของคุณยังคึกจัด วิ่งสปีดแบบ 4x100 วนไปรอบๆบ้าน อาการ Zoomies ไม่ยอมหลับยอมนอน ทำยังไงถึงจะสยบพลังงานก้อนนี้ให้อยู่นิ่งๆ ได้ซะที?', 2, 1, 'ชวนเล่นเกม "ซ่อนหาขนม" ให้ใช้จมูกดมหาของสัก 10 นาที สำหรับบีเกิล การใช้พลังงานสมองและจมูก ทำให้เหนื่อยได้เร็วกว่าการวิ่งเล่นเฉยๆ การให้ดมกลิ่นหาขนมสั้นๆ จะช่วยกระตุ้นสัญชาตญาณและทำให้น้องรู้สึกฟิน พึงพอใจ และหลับปุ๋ยไปเอง'),
('คุณปล่อยเจ้าตัวแสบไว้ในคอกแค่แป๊บเดียวเพื่อไปเข้าห้องน้ำ พอกลับมาอีกที... ขาโต๊ะไม้ตัวโปรดเต็มไปด้วยรอยแทะเยินไปหมด! แถมน้องหมายังนั่งกระดิกหางทำหน้าซื่อตาใสอีก สาเหตุหลักๆ ที่น้องชอบแทะของคืออะไร?', 2, 1, 'ลูกหมาวัยนี้ฟันน้ำนมกำลังขึ้นและเตรียมจะผลัด เหงือกจะคันยุบยิบตลอดเวลา ถ้าเราไม่เตรียมของเล่นสำหรับแทะเอาไว้ให้พร้อม เฟอร์นิเจอร์ในบ้านและรองเท้าของคุณคือเป้าหมายถัดไปแน่นอน');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('คุณปล่อยน้องหมาของคุณไว้ในสวนหลังบ้านเพียงลำพังประมาณ 1 ชั่วโมง เมื่อกลับมาพบว่าเขาขุดหลุมขนาดใหญ่ลึกเข้าไปใต้รั้วบ้านและกำลังพยายามมุดออกไป พฤติกรรมนี้เกิดจากสาเหตุหลักอะไรในสายพันธุ์นี้?', 2, 2, 'ได้กลิ่นสัตว์เล็กนอกรั้ว จึงขุดตามสัญชาตญาณนักล่าและบวกกับความเบื่อหน่าย บีเกิลวัยรุ่นมีพลังงานสูงและขี้เบื่อ จมูกไวต่อกลิ่นสัตว์อื่น จึงได้ฉายาว่า "Houdini" (นักหลบหนี) การปล่อยไว้ตามลำพังโดยไม่มีกิจกรรมให้ทำ มักจบลงด้วยการขุดทำลายรั้ว'),
('คุณวางจานหมูปิ้งไว้บนโต๊ะกินข้าว แล้วหันหลังไปหยิบน้ำในตู้เย็นแค่ 3 วินาที หันกลับมาอีกที... หมูปิ้งหายวับไปกับตา! พร้อมกับเจ้าบีเกิลที่นั่งเลียปากแผล็บๆ อยู่ใต้โต๊ะ วิธีแก้ปัญหานิสัยชอบปีนป่ายขโมยอาหาร ที่ดีที่สุดคืออะไร?', 2, 2, 'บริหารจัดการสิ่งแวดล้อมใหม่ เก็บของกินให้พ้นระยะสายตาและการเอื้อมถึงทุกครั้ง บีเกิลวัยรุ่นตัวสูงพอที่จะยืดขาหน้าเกาะขอบโต๊ะได้สบายๆ การทำโทษมักไม่ได้ผลเพราะน้องได้ "รางวัล" ไปแล้ว การจัดการสภาพแวดล้อมและฝึกคำสั่งจึงสำคัญที่สุด');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('น้องหมาของคุณกินอาหารมื้อหลักหมดเกลี้ยงภายใน 15 วินาที หลังจากนั้นเขาก็เดินไปด้อมๆ มองๆ แถวถังขยะในครัว และมานั่งทำตาละห้อยขออาหารจากโต๊ะกินข้าวของคุณ เพื่อสุขภาพที่ดีของเขา คุณควรใช้วิธีใด?', 2, 3, 'เปลี่ยนถังขยะเป็นแบบล็อคฝาแน่นหนา และเปลี่ยนมาใช้ชามใส่อาหารแบบฝึกกินช้า (Slow Feeder) บีเกิลถูกขนานนามว่าเป็นสุนัขที่ไม่มีวันอิ่ม การใช้ Slow Feeder จะช่วยยืดเวลากิน ป้องกันลำไส้อุดตันจากการคุ้ยขยะกิน'),
('จู่ๆ รถพยาบาลก็เปิดไซเรนวิ่งผ่านหน้าบ้านไป เจ้าบีเกิลวัยรุ่นของคุณแหงนหน้าขึ้นฟ้า แล้วหอนยาวๆ รับเสียงไซเรนซะงั้น! ทำไมต้องหอนตอบรับเสียงแบบนี้ด้วยล่ะ?', 2, 3, 'คลื่นความถี่เสียงไซเรนไปกระตุ้นสัญชาตญาณการหอนรวมฝูง เหมือนหมาป่า พฤติกรรมการส่งเสียงหอน เป็นสัญชาตญาณดิบ เมื่อได้ยินเสียงแหลมสูง น้องจะรู้สึกว่ามีคนในฝูงกำลังส่งสัญญาณมา เลยต้องหอนตอบรับกลับไปเพื่อบอกตำแหน่ง'),
('คุณเรียกชื่อน้องหมามา 10 รอบ แต่น้องนอนหลับตาพริ้ม ทำหูทวนลมเป็นรูปปั้นหิน แต่พอคุณเอื้อมมือไปหยิบ "ถุงขนมก็อบแก๊บ" แล้วเกิดเสียงดังแกรบเดียว น้องวาร์ปมาโผล่ตรงหน้าภายใน 1 วินาที! อาการแบบนี้ แก้ยังไงให้ได้ผลระยะยาว?', 2, 3, 'ฝึกทบทวนคำสั่งพื้นฐานใหม่ โดยใช้ขนมเป็นรางวัล แต่ค่อยๆ ลดการให้ขนมลงและเปลี่ยนเป็นคำชมแทน บีเกิลเป็นหมาดื้อเงียบ ถ้าไม่มี "ผลประโยชน์" มาล่อ ก็ยากที่จะยอมทำตาม การฝึกด้วยรางวัลเชิงบวกอย่างสม่ำเสมอจึงสำคัญ'),
('คุณออกไปซื้อของหน้าปากซอยแค่ 10 นาที กลับมาถึงบ้านแทบช็อก! ถังขยะในครัวล้มระเนระนาด เศษอาหารกระจายเกลื่อนพื้น เพื่อป้องกันไม่ให้น้องต้องไปจบที่ห้องฉุกเฉินเพราะลำไส้อุดตัน คุณต้องอัปเกรดบ้านยังไง?', 2, 3, 'ซื้อถังขยะแบบมีฝาล็อคแน่นหนา หรือเก็บถังขยะซ่อนไว้ในตู้ปิดมิดชิดทุกครั้ง การดุหลังจากเกิดเหตุไปแล้วไม่ได้ผลเพราะน้องจำไม่ได้ การจัดการสิ่งแวดล้อม ปิดโอกาสไม่ให้เข้าถึงถังขยะได้ คือทางออกที่ง่ายและปลอดภัยที่สุด');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('บีเกิลวัย 9 ปีของคุณซึ่งปกติชอบกระโดดขึ้นมานอนบนโซฟากับคุณ จู่ๆ วันนี้เขายืนลังเลหน้าโซฟา ไม่ยอมกระโดดขึ้นมา เดินหลังโก่งผิดปกติ และร้องเสียงหลงเมื่อคุณพยายามช้อนตัวอุ้ม อาการนี้น่าจะบ่งบอกถึงปัญหาสุขภาพใด?', 2, 4, 'ภาวะหมอนรองกระดูกทับเส้นประสาท หรือปัญหาเกี่ยวกับไขสันหลัง บีเกิลเป็นสุนัขที่มีช่วงลำตัวยาวและขาสั้น เมื่ออายุมากขึ้น ประกอบกับน้ำหนักตัวที่มักจะเกินมาตรฐาน ทำให้กระดูกสันหลังต้องรับภาระหนัก'),
('คุณคุมอาหารบีเกิลของคุณแบบเป๊ะเวอร์ ชั่งตวงทุกมื้อ แถมให้กินสูตรหมาแก่แคลอรีต่ำ แต่ทำไมน้ำหนักถึงยังพุ่งเอาๆ แถมวันๆ เอาแต่นอนซึม ขนร่วง ไม่ร่าเริงเหมือนก่อน สาเหตุน่าจะมาจากข้อไหน?', 2, 4, 'ภาวะต่อมไทรอยด์ทำงานต่ำ ทำให้ระบบเผาผลาญพังพินาศ บีเกิลเป็นหนึ่งในสายพันธุ์ที่เป็นโรคไทรอยด์ต่ำกันเยอะมาก โรคนี้จะทำให้ระบบเผาผลาญทำงานช้าลงสุดๆ แถมยังทำให้ขี้หนาว ขนร่วง และเชื่องช้า ผู้เลี้ยงต้องพาไปตรวจเลือดและรับยาปรับฮอร์โมน');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('ลูกหมาโกลเด้นวัย 5 เดือนของคุณกำลังพลังงานล้นเหลือ กิจกรรมออกกำลังกายแบบไหนที่คุณควร "หลีกเลี่ยง" เพื่อป้องกันปัญหาสุขภาพในระยะยาว?', 3, 1, 'การโยนจานร่อน ให้กระโดดลอยตัวสูงๆ โกลเด้นเป็นสุนัขพันธุ์ใหญ่ที่กระดูกและข้อต่อยังเจริญเติบโตไม่เต็มที่จนกว่าจะอายุประมาณ 1-1.5 ปี การกระโดดสูงๆ หรือวิ่งกระแทกแรงๆ ในวัยเด็ก จะเพิ่มความเสี่ยงให้กระดูกผิดรูปและเกิดโรคข้อสะโพกเสื่อมก่อนวัยอันควรได้'),
('คุณเพิ่งได้รับเลี้ยงเจ้าสี่ขา และกำลังจัดเตรียมมุมให้อาหาร คุณควรจัดการกับ "ชามอาหาร" อย่างไรเพื่อให้ดีต่อสุขภาพของพวกเขาที่สุด?', 3, 1, 'วางชามอาหารไว้บนพื้นราบตามปกติ งานวิจัยทางการแพทย์ในปัจจุบันพบว่า การให้สุนัขพันธุ์ใหญ่กินอาหารจากชามที่ยกสูง กลับเป็นปัจจัยที่เพิ่มความเสี่ยงให้เกิดภาวะกระเพาะครากและบิดตัว มากกว่าการวางชามบนพื้นปกติ'),
('โกลเด้นของคุณอายุครบ 6 เดือนแล้ว คลินิกสัตว์แพทย์ส่งโปรโมชั่น "ทำหมันราคาพิเศษ" มาให้ คุณควรพาน้องไปขึ้นเขียงเลยตอนนี้หรือไม่?', 3, 1, 'ยังก่อน ควรอดใจรอให้อายุครบ 1-2 ปีก่อน เพื่อให้กระดูกและข้อต่อเจริญเติบโตเต็มที่ อันนี้เป็นจุดหักมุมที่คนมักพลาด สำหรับหมาพันธุ์ใหญ่ ฮอร์โมนเพศมีส่วนสำคัญมากในการปิดปลายกระดูก หากรีบทำหมันเร็วเกินไป กระดูกจะยืดผิดปกติและเพิ่มความเสี่ยงโรคข้อสะโพกเสื่อม');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('คุณเพิ่งกลับถึงบ้าน น้องหมาของคุณวิ่งหูตั้งมาต้อนรับ พร้อมกับคาบ "รองเท้าคู่โปรดของคุณ" ไว้ในปากและแกว่งหางไปมา คุณควรจัดการกับสถานการณ์นี้อย่างไรในฐานะผู้เลี้ยงที่เข้าใจสายพันธุ์?', 3, 2, 'หยิบของเล่นสำหรับสุนัขมาหลอกล่อให้เขาคายรองเท้า แล้วชมเชยเมื่อเขาคาบของเล่นแทน โกลเด้นมีสัญชาตญาณชอบคาบสิ่งของมาให้เจ้าของเพื่อแสดงความรัก การดุหรือแย่งของจะทำให้เขาสับสน การเบี่ยงเบนความสนใจด้วยของเล่นจึงเป็นวิธีฝึกที่ถูกต้องที่สุด'),
('วันหยุดสุดสัปดาห์ คุณพาน้องหมาของคุณไปว่ายน้ำที่สระว่ายน้ำสุนัข ซึ่งเป็นกิจกรรมที่พวกเขาหลงรักมากๆ หลังจากว่ายน้ำเสร็จและเช็ดตัวจนแห้งแล้ว มีอวัยวะส่วนไหนที่คุณ "ห้ามลืม" ทำความสะอาดและเช็ดให้แห้งสนิทเด็ดขาด?', 3, 2, 'ด้านในช่องหู! โกลเด้นเป็นสุนัขหูตก ทำให้ระบายอากาศได้ไม่ดี หากปล่อยให้ช่องหูชื้นหลังจากการว่ายน้ำหรืออาบน้ำ จะเสี่ยงต่อการหมักหมมและเกิดโรคหูอักเสบจากยีสต์หรือแบคทีเรียได้ง่ายมาก'),
('คุณตวงอาหารเม็ดให้น้องหมาในปริมาณที่เหมาะสมต่อวันเรียบร้อยแล้ว แต่พอกินหมด เขาก็ยังมานั่งทำตาละห้อย น้ำลายสอ และเอาคางเกยตักคุณเพื่อขออาหารเพิ่ม คุณควรตัดสินใจอย่างไร?', 3, 2, 'ใจแข็งไม่ให้อาหารหลักเพิ่ม แต่อาจให้ของว่างแคลอรีต่ำ เช่น แครอทต้ม หรือพาไปเดินเล่นแทน โกลเด้นเป็นสายพันธุ์ที่กินเก่งมาก การตามใจเรื่องกินจะนำไปสู่ "โรคอ้วน" ซึ่งเป็นอันตรายอย่างยิ่ง เพราะจะไปเพิ่มภาระให้กับข้อต่อ');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('ในช่วงหน้าฝน อากาศชื้น คุณสังเกตเห็นหมาโกลเด้นของคุณเกาและเลียผิวหนังบริเวณหลังอย่างหนักจนขนร่วงเป็นหย่อม ผิวหนังแดงช้ำและมีน้ำเหลืองเยิ้ม นี่คืออาการของโรคผิวหนังชนิดใดที่พบบ่อยในสุนัขพันธุ์นี้?', 3, 3, 'ผิวหนังอักเสบเฉียบพลัน (Hot Spots) มักเกิดกับสุนัขที่มีขนสองชั้นและหนาอย่างโกลเด้น เมื่อผิวหนังอับชื้น เช่น หลังอาบน้ำแล้วเป่าขนชั้นในไม่แห้งสนิท จะทำให้แบคทีเรียเจริญเติบโตอย่างรวดเร็วและลุกลามเป็นแผลใหญ่ได้ภายในคืนเดียว');
INSERT INTO questions (scenario_text, breed_id, current_day, answer_text) VALUES
('โกลเด้นของคุณอายุครบ 6 ปีแล้ว นอกจากการฉีดวัคซีนประจำปี การตรวจคัดกรองสุขภาพด้านใดที่คุณควรให้ความสำคัญมากที่สุดเป็นพิเศษสำหรับสุนัขสายพันธุ์นี้?', 3, 4, 'การอัลตราซาวนด์และเอ็กซเรย์ เพื่อคัดกรองโรคมะเร็ง โกลเด้น รีทรีฟเวอร์ เป็นสายพันธุ์ที่มีอัตราการเสียชีวิตจากโรคมะเร็งสูงถึง 60% การตรวจพบความผิดปกติได้เร็วตั้งแต่วัยกลางคนจึงเป็นกุญแจสำคัญในการยืดอายุขัย');
